function normalizeUrl(rawUrl) {
  let value = String(rawUrl || '').trim();
  if (!value) return null;
  if (!/^https?:\/\//i.test(value)) value = `https://${value}`;
  try {
    const url = new URL(value);
    url.hash = '';
    const host = url.hostname.replace(/^www\./i, '').toLowerCase();
    const pathname = (url.pathname || '/').replace(/\/+/g, '/');
    const normalizedPath = pathname === '/' ? '/' : pathname.replace(/\/$/, '');
    const search = url.search || '';
    return `${url.protocol}//${host}${normalizedPath}${search}`;
  } catch {
    return null;
  }
}

function classifyTechnicalStatus(originalUrl, normalizedUrl) {
  if (!originalUrl || !String(originalUrl).trim()) {
    return { fetch_status: 'INVALID_SOURCE_URL', error_code: 'INVALID_SOURCE_URL', error_message: 'Missing source URL' };
  }
  if (!normalizedUrl) {
    return { fetch_status: 'INVALID_SOURCE_URL', error_code: 'INVALID_SOURCE_URL', error_message: 'Source URL could not be normalized' };
  }
  return { fetch_status: 'PENDING', error_code: null, error_message: null };
}

const originalUrl = $json.source_url_original ?? $json.url ?? null;
const normalizedUrl = normalizeUrl(originalUrl);
const tech = classifyTechnicalStatus(originalUrl, normalizedUrl);

return {
  json: {
    run_id: $json.run_id,
    source_id: $json.source_id ?? $json.id ?? null,
    source_name: $json.source_name ?? $json.name ?? null,
    source_url_original: originalUrl,
    source_url_normalized: normalizedUrl,
    platform: String($json.platform || 'website').toLowerCase() === 'web' ? 'website' : String($json.platform || 'website').toLowerCase(),
    source_kind: $json.source_kind ?? $json.sourceKind ?? 'WEBSITE',
    trust_score: Number($json.trust_score ?? 50),
    discovery_method: $json.discovery_method ?? null,
    source_notes: $json.notes ?? null,
    fetch_status: tech.fetch_status,
    profile_status: 'PENDING',
    parse_status: 'PENDING',
    validation_status: 'PENDING',
    error_code: tech.error_code,
    error_message: tech.error_message,
  }
};

const blockedFragments = [
  '/impressum', '/datenschutz', '/privacy', '/kontakt', '/contact', '/login', '/signin', '/spende', '/donation'
];

const normalizedUrl = typeof $json.source_url_normalized === 'string' ? $json.source_url_normalized : null;
if (!normalizedUrl) {
  return [];
}

const lower = normalizedUrl.toLowerCase();
if (blockedFragments.some((fragment) => lower.includes(fragment))) {
  return [];
}

return { json: { ...$json, fetch_url: normalizedUrl } };

function classifyFetch(item) {
  const statusCode = Number(item.statusCode ?? item.status_code ?? 0);
  const body = typeof item.body === 'string'
    ? item.body
    : typeof item.data === 'string'
      ? item.data
      : item.data && typeof item.data.body === 'string'
        ? item.data.body
        : null;
  const rawError = item.error ? String(item.error.message || item.error || '') : '';
  const finalUrl = typeof item.url === 'string'
    ? item.url
    : typeof item.final_url === 'string'
      ? item.final_url
      : item.source_url_normalized;

  if (item.fetch_status === 'INVALID_SOURCE_URL') {
    return { fetch_status: 'INVALID_SOURCE_URL', error_code: 'INVALID_SOURCE_URL', error_message: item.error_message || 'Invalid source URL', body, statusCode, finalUrl };
  }
  if (/ENOTFOUND/i.test(rawError)) {
    return { fetch_status: 'DNS_ERROR', error_code: 'DNS_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (/EPROTO|SSL|TLS/i.test(rawError)) {
    return { fetch_status: 'TLS_ERROR', error_code: 'TLS_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (/timeout/i.test(rawError)) {
    return { fetch_status: 'FETCH_TIMEOUT', error_code: 'FETCH_TIMEOUT', error_message: rawError, body, statusCode, finalUrl };
  }
  if (rawError) {
    return { fetch_status: 'UNKNOWN_ERROR', error_code: 'UNKNOWN_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (statusCode >= 400) {
    return { fetch_status: 'HTTP_ERROR', error_code: 'HTTP_ERROR', error_message: `HTTP ${statusCode}`, body, statusCode, finalUrl };
  }
  if (typeof body !== 'string' || body.trim().length < 80) {
    return { fetch_status: 'EMPTY_RESPONSE', error_code: 'EMPTY_RESPONSE', error_message: 'Response body missing or too short', body, statusCode, finalUrl };
  }
  if (/captcha|access denied|forbidden|enable cookies|anmelden|einloggen|login/i.test(body)) {
    return { fetch_status: 'BLOCKED', error_code: 'BLOCKED', error_message: 'Blocked or login wall', body, statusCode, finalUrl };
  }
  return { fetch_status: 'SUCCESS', error_code: null, error_message: null, body, statusCode, finalUrl };
}

const result = classifyFetch($json);
return {
  json: {
    ...$json,
    fetch_status: result.fetch_status,
    profile_status: result.fetch_status === 'SUCCESS' ? 'READY' : 'FETCH_ERROR',
    error_code: result.error_code,
    error_message: result.error_message,
    status_code: result.statusCode || null,
    final_url: result.finalUrl || $json.source_url_normalized || null,
    html: result.body,
  }
};

const POSITIVE = ['veranstaltung','veranstaltungen','event','events','termin','termine','kalender','programm','seminar','workshop','konferenz'];
const NEGATIVE = ['impressum','datenschutz','privacy','kontakt','contact','spende','donation','login'];
const anchorRegex = new RegExp('<a\\b[^>]*?href\\s*=\\s*(?:"([^"]*)"|\'([^\']*)\'|([^\\s>]+))[^>]*>([\\s\\S]*?)<\\/a>', 'gi');

function normalizeUrl(href, baseUrl) {
  try {
    const value = String(href || '').trim();
    if (!value || /^(#|mailto:|tel:|javascript:)/i.test(value)) return null;
    const url = new URL(value, baseUrl);
    url.hash = '';
    return url.toString();
  } catch {
    return null;
  }
}

function decodeHtml(text) {
  return String(text || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

if ($json.fetch_status !== 'SUCCESS') {
  return {
    json: {
      run_id: $json.run_id,
      source_id: $json.source_id,
      source_name: $json.source_name,
      source_url_original: $json.source_url_original,
      source_url_normalized: $json.source_url_normalized,
      final_url: $json.final_url || $json.source_url_normalized,
      fetch_status: $json.fetch_status,
      profile_status: 'FETCH_ERROR',
      status: 'fetch_error',
      event_links: [],
      non_event_candidates: [],
      debug_links: [],
      errors: [{ code: $json.error_code || $json.fetch_status, message: $json.error_message || 'Fetch failed' }],
    }
  };
}

const html = typeof $json.html === 'string' ? $json.html : '';
const baseUrl = $json.final_url || $json.source_url_normalized || $json.source_url_original;
const seen = new Set();
const event_links = [];
const non_event_candidates = [];
const debug_links = [];
let match;

while ((match = anchorRegex.exec(html)) !== null) {
  const rawHref = String(match[1] || match[2] || match[3] || '').trim();
  const normalized = normalizeUrl(rawHref, baseUrl);
  if (!normalized || seen.has(normalized)) continue;
  seen.add(normalized);
  const label = decodeHtml(match[4] || rawHref);
  const combined = `${normalized} ${label}`.toLowerCase();
  const positive_keywords = POSITIVE.filter((token) => combined.includes(token));
  const negative_keywords = NEGATIVE.filter((token) => combined.includes(token));
  const score = positive_keywords.length * 3 - negative_keywords.length * 5 + (/\b\d{1,2}[./-]\d{1,2}/.test(label) ? 1 : 0);
  const accepted = positive_keywords.length > 0 && negative_keywords.length === 0;
  const reasons = [];
  if (positive_keywords.length) reasons.push(`positive:${positive_keywords.join(',')}`);
  if (negative_keywords.length) reasons.push(`negative:${negative_keywords.join(',')}`);
  if (/\b\d{1,2}[./-]\d{1,2}/.test(label)) reasons.push('date_text');
  const debug = { url: normalized, label, accepted, score, positive_keywords, negative_keywords, reasons };
  debug_links.push(debug);
  const candidate = {
    url: normalized,
    label,
    score,
    source: 'anchor',
    positive_keywords,
    negative_keywords,
    reasons,
  };
  if (accepted) event_links.push(candidate);
  else if (positive_keywords.length || negative_keywords.length) non_event_candidates.push(candidate);
}

return {
  json: {
    run_id: $json.run_id,
    source_id: $json.source_id,
    source_name: $json.source_name,
    source_url_original: $json.source_url_original,
    source_url_normalized: $json.source_url_normalized,
    final_url: $json.final_url || $json.source_url_normalized,
    fetch_status: $json.fetch_status,
    profile_status: event_links.length > 0 ? 'PROFILED' : 'NO_CANDIDATES',
    status: 'ok',
    event_links,
    non_event_candidates,
    debug_links,
    errors: [],
  }
};

const output = [];
for (const item of $input.all()) {
  const source = item.json || {};
  const eventLinks = Array.isArray(source.event_links) ? source.event_links : [];
  for (const candidate of eventLinks) {
    const originalUrl = typeof candidate?.url === 'string' ? candidate.url : null;
    if (!originalUrl) continue;
    let normalizedUrl = null;
    try {
      const url = new URL(originalUrl, source.final_url || source.source_url_normalized || source.source_url_original || undefined);
      url.hash = '';
      normalizedUrl = url.toString();
    } catch {}
    if (!normalizedUrl) continue;
    output.push({
      json: {
        run_id: source.run_id,
        source_id: source.source_id,
        source_name: source.source_name,
        source_url_original: source.source_url_original,
        source_url_normalized: source.source_url_normalized,
        candidate_url_original: originalUrl,
        candidate_url_normalized: normalizedUrl,
        candidate_label: candidate.label || null,
        candidate_score: Number(candidate.score || 0),
        candidate_reasons: Array.isArray(candidate.reasons) ? candidate.reasons : [],
        fetch_status: 'PENDING',
        profile_status: source.profile_status || 'PROFILED',
        parse_status: 'PENDING',
        validation_status: 'PENDING',
      }
    });
  }
}
return output;

const url = typeof $json.candidate_url_normalized === 'string' ? $json.candidate_url_normalized : null;
if (!url) {
